@staticmethod
def subtract(num1, num2):
    """
        把两个大数字相减。
        :param num1: 第一个要被减去的数字，字符串。
        :param num2: 第二个要减去的数字，字符串。
        :return: 两个数字的差，字符串。
        >>> bigNum = BigNumCalculator()
        >>> bigNum.subtract("12345678901234567890", "98765432109876543210")
        '-86419753208641975320'

        """
    negative = False
    if len(num1) < len(num2):
        negative = True
    elif len(num1) == len(num2):
        for i in range(len(num1)):
            if int(num1[i]) < int(num2[i]):
                negative = True
                break
            elif int(num1[i]) > int(num2[i]):
                break
    if negative:
        num1, num2 = (num2, num1)
    max_length = max(len(num1), len(num2))
    num1 = num1.zfill(max_length)
    num2 = num2.zfill(max_length)
    borrow = 0
    result = []
    for i in range(max_length - 1, -1, -1):
        digit1 = int(num1[i])
        digit2 = int(num2[i])
        digit1 -= borrow
        borrow = 0
        if digit1 < digit2:
            digit1 += 10
            borrow = 1
        digit_diff = digit1 - digit2
        result.insert(0, str(digit_diff))
    while len(result) > 1 and result[0] == '0':
        result.pop(0)
    if negative:
        result.insert(0, '-')
    return ''.join(result)

def calculate_binary_info(self):
    """
        计算二进制字符串的信息，包括0和1的百分比，以及二进制字符串的总长度。
        >>> bdp = BinaryDataProcessor("0110100001100101011011000110110001101111")
        >>> bdp.calculate_binary_info()
        {'Zeroes': 0.475, 'Ones': 0.525, 'Bit length': 40}

        """
    if not self.binary_string:
        return {'Zeroes': 0.0, 'Ones': 0.0, 'Bit length': 0}
    total_length = len(self.binary_string)
    zero_count = self.binary_string.count('0')
    one_count = self.binary_string.count('1')
    zero_percentage = zero_count / total_length
    one_percentage = one_count / total_length
    return {'Zeroes': round(zero_percentage, 3), 'Ones': round(one_percentage, 3), 'Bit length': total_length}

@staticmethod
def check(args):
    """
        检查参数是否合法，args 必须大于或等于 0 且必须是偶数，如果不是，则引发 ValueError。
        :param args: 要检查的参数，列表。
        :return: None。
        >>> bit_status_util = BitStatusUtil()
        >>> bit_status_util.check([2,3,4])
        Traceback (most recent call last):
        ...
        ValueError: 3 不是偶数
        """
    for arg in args:
        if not isinstance(arg, int):
            raise ValueError(f'{arg} 不是整数')
        if arg < 0:
            raise ValueError(f'{arg} 小于 0')
        if arg % 2 != 0:
            raise ValueError(f'{arg} 不是偶数')

def remove_book(self, title, quantity):
    """
        从按书名排序的库存中移除一本或多本书籍。
        如果输入无效则引发错误。
        :param title: str，书名
        :param quantity: int
        """
    if not isinstance(title, str):
        raise TypeError('Title must be a string')
    if not isinstance(quantity, int):
        raise TypeError('Quantity must be an integer')
    if quantity <= 0:
        raise ValueError('Quantity must be positive')
    if title not in self.inventory:
        raise ValueError(f"Book '{title}' not found in inventory")
    if self.inventory[title] < quantity:
        raise ValueError(f"Cannot remove {quantity} copies of '{title}'. Only {self.inventory[title]} available")
    self.inventory[title] -= quantity
    if self.inventory[title] == 0:
        del self.inventory[title]

def calculate(self, expression):
    """
        计算给定表达式的值
        :param expression: 字符串，给定的表达式
        :return: 如果成功，返回表达式的值；否则，返回 None
        >>> calculator = Calculator()
        >>> calculator.calculate('1+2-3')
        0.0
        """
    if not expression:
        return None
    operand_stack = []
    operator_stack = []
    i = 0
    n = len(expression)
    while i < n:
        char = expression[i]
        if char.isdigit() or char == '.':
            j = i
            while j < n and (expression[j].isdigit() or expression[j] == '.'):
                j += 1
            try:
                num = float(expression[i:j])
            except ValueError:
                return None
            operand_stack.append(num)
            i = j
        elif char in self.operators:
            while operator_stack and self.precedence(operator_stack[-1]) >= self.precedence(char):
                operand_stack, operator_stack = self.apply_operator(operand_stack, operator_stack)
            operator_stack.append(char)
            i += 1
        elif char == '(':
            operator_stack.append(char)
            i += 1
        elif char == ')':
            while operator_stack and operator_stack[-1] != '(':
                operand_stack, operator_stack = self.apply_operator(operand_stack, operator_stack)
            if not operator_stack or operator_stack[-1] != '(':
                return None
            operator_stack.pop()
            i += 1
        elif char.isspace():
            i += 1
        else:
            return None
    while operator_stack:
        if operator_stack[-1] == '(':
            return None
        operand_stack, operator_stack = self.apply_operator(operand_stack, operator_stack)
    if len(operand_stack) != 1 or operator_stack:
        return None
    return operand_stack[0]

def generate_primes(self):
    """
        使用钱德拉塞卡筛法生成指定限制内的素数。
        :return: list, 一个素数列表
        >>> cs = ChandrasekharSieve(20)
        >>> cs.generate_primes()
        [2, 3, 5, 7, 11, 13, 17, 19]

        """
    if self.n < 2:
        return []
    is_prime = [True] * (self.n + 1)
    is_prime[0] = is_prime[1] = False
    if self.n >= 2:
        for i in range(4, self.n + 1, 2):
            is_prime[i] = False
    p = 3
    while p * p <= self.n:
        if is_prime[p]:
            for i in range(p * p, self.n + 1, 2 * p):
                is_prime[i] = False
        p += 2
    primes = []
    for i in range(2, self.n + 1):
        if is_prime[i]:
            primes.append(i)
    return primes

